import tarfile
import os
from pathlib import Path


def extract_tar_file(tar_path, destination_dir):
    """
    Securely extracts a tar file to a destination directory.
    
    Args:
        tar_path: Path to the tar file to extract
        destination_dir: Directory where files will be extracted
    
    Raises:
        ValueError: If paths are invalid or contain path traversal attempts
        tarfile.TarError: If the tar file is invalid or corrupted
    """
    # Validate and normalize paths
    tar_path = Path(tar_path).resolve()
    destination_dir = Path(destination_dir).resolve()
    
    # Verify tar file exists and is a file
    if not tar_path.exists():
        raise ValueError(f"Tar file does not exist: {tar_path}")
    if not tar_path.is_file():
        raise ValueError(f"Tar path is not a file: {tar_path}")
    
    # Create destination directory if it doesn't exist
    destination_dir.mkdir(parents=True, exist_ok=True)
    
    # Open and extract tar file with security checks
    with tarfile.open(tar_path, 'r:*') as tar:
        # Validate each member before extraction
        for member in tar.getmembers():
            # Resolve the member path to prevent path traversal
            member_path = (destination_dir / member.name).resolve()
            
            # Ensure the resolved path is within the destination directory
            if not str(member_path).startswith(str(destination_dir)):
                raise ValueError(f"Path traversal attempt detected: {member.name}")
            
            # Check for absolute paths
            if member.name.startswith('/') or member.name.startswith('..'):
                raise ValueError(f"Unsafe path in tar archive: {member.name}")
        
        # Extract all files after validation
        tar.extractall(path=destination_dir, filter='data')